solve(Events) ->
    process(Events, {0, 0}).

process([], State) ->
    State;
process([E | Rest], State) ->
    {Score, Counter} = State,

    if Counter >= 10 ->
        State;
    true ->
        % Determine NextState based on event E
        case E of
            <<"0">> -> NextState = {Score + 0, Counter};
            <<"1">> -> NextState = {Score + 1, Counter};
            <<"2">> -> NextState = {Score + 2, Counter};
            <<"3">> -> NextState = {Score + 3, Counter};
            <<"4">> -> NextState = {Score + 4, Counter};
            <<"6">> -> NextState = {Score + 6, Counter};
            <<"W">> -> NextState = {Score, Counter + 1};
            <<"WD">> -> NextState = {Score + 1, Counter};
            <<"NB">> -> NextState = {Score + 1, Counter};
            _ -> NextState = {Score, Counter} % Should not happen based on constraints
        end,

        {S', C'} = NextState,

        % Check stopping condition: Counter becomes 10
        if C' =:= 10 ->
            NextState;
        true ->
            process(Rest, NextState)
        end.
% Note: The return value {Score, Counter} naturally represents the required list [Score, Counter].

