solve([Events]) ->
    process(Events, 0, 0).

%% process(List, Score, Counter) -> [Score, Counter]
process([], Score, Counter) ->
    [Score, Counter];

process([Event | Rest], Score, Counter) ->
    NewScore = Score,
    NewCounter = Counter,

    case Event of
        % Digit events: add the digit value
        <<"0">> -> NewScore = Score;
        <<"1">> -> NewScore = Score + 1;
        <<"2">> -> NewScore = Score + 2;
        <<"3">> -> NewScore = Score + 3;
        <<"4">> -> NewScore = Score + 4;
        <<"6">> -> NewScore = Score + 6;

        % Control events
        <<"W">> -> NewCounter = Counter + 1;

        <<"WD">> -> NewScore = Score + 1;

        <<"NB">> -> NewScore = Score + 1;

        _ -> 
            % Should not happen given constraints, but handles unexpected input
            [Score, Counter] 
    end,

    % Check stopping condition: Counter became 10 after processing this event
    if NewCounter == 10 ->
        [NewScore, NewCounter];
    true ->
        % Continue processing the rest of the list
        process(Rest, NewScore, NewCounter)
    end.

